532     unsigned NewPeelCount = DesiredPeelCount;
533     const SCEV *IterVal = AddRec->evaluateAtIteration(
534         SE.getConstant(AddRec->getType(), NewPeelCount), SE);
535     if (!PeelWhilePredicateIsKnown(NewPeelCount, IterVal, BoundSCEV, Step,
536                                    Pred))
537       return;
538     DesiredPeelCount = NewPeelCount;
539   };
540 
541   for (BasicBlock *BB : L.blocks()) {
542     for (Instruction &I : *BB) {
543       if (SelectInst *SI = dyn_cast<SelectInst>(&I))
544         ComputePeelCount(SI->getCondition(), 0);
545       if (MinMaxIntrinsic *MinMax = dyn_cast<MinMaxIntrinsic>(&I))
546         ComputePeelCountMinMax(MinMax);
547     }
548 
549     auto *BI = dyn_cast<BranchInst>(BB->getTerminator());
550     if (!BI || BI->isUnconditional())
551       continue;
552 
553     // Ignore loop exit condition.
554     if (L.getLoopLatch() == BB)
555       continue;
556 
557     ComputePeelCount(BI->getCondition(), 0);
558   }
559 
560   return {DesiredPeelCount, DesiredPeelCountLast};
561 }
