563 /// This "heuristic" exactly matches implicit behavior which used to exist
564 /// inside getLoopEstimatedTripCount.  It was added here to keep an
565 /// improvement inside that API from causing peeling to become more aggressive.
566 /// This should probably be removed.
567 static bool violatesLegacyMultiExitLoopCheck(Loop *L) {
568   BasicBlock *Latch = L->getLoopLatch();
569   if (!Latch)
570     return true;
571 
572   BranchInst *LatchBR = dyn_cast<BranchInst>(Latch->getTerminator());
573   if (!LatchBR || LatchBR->getNumSuccessors() != 2 || !L->isLoopExiting(Latch))
574     return true;
575 
576   assert((LatchBR->getSuccessor(0) == L->getHeader() ||
577           LatchBR->getSuccessor(1) == L->getHeader()) &&
578          "At least one edge out of the latch must go to the header");
579 
580   SmallVector<BasicBlock *, 4> ExitBlocks;
581   L->getUniqueNonLatchExitBlocks(ExitBlocks);
582   return any_of(ExitBlocks, [](const BasicBlock *EB) {
583       return !EB->getTerminatingDeoptimizeCall();
584     });
585 }
